from fastapi import FastAPI

app = FastAPI()

@app.get('/')
def read_root():
    return {"Hello": "World"}

@app.get('/items/')
def read_item(skip: int = 0, limit: int = 10):
    return {"skip": skip, "limit": limit}

from pydantic import BaseModel

class Item(BaseModel):
    name: str
    price: float

@app.post('/items/')
def create_item(item: Item):
    return item

@app.get('/items/{item_id}', response_model=Item)
def read_item(item_id: int):
    return {"name": "Item Name", "price": 10.5}

class Item(BaseModel):
    name: str
    price: float

@app.get('/items/{item_id}', response_model=Item, response_model_exclude_unset=True)
def read_item(item_id: int):
    return {"name": "Item Name", "price": 10.5}

from fastapi import Depends

def common_parameters(q: str = None):
    return {"q": q}

@app.get('/items/')
def read_items(commons: dict = Depends(common_parameters)):
    return commons

class CommonQueryParams:
    def __init__(self, q: str = None):
        self.q = q

@app.get('/items/')
def read_items(commons: CommonQueryParams = Depends()):
    return {"q": commons.q}

def query_extractor(q: str = None):
    return q

def query_or_cookie_extractor(q: str = Depends(query_extractor), last_query: str = None):
    if not q:
        return last_query
    return q

@app.get('/items/')
def read_query(query_or_default: str = Depends(query_or_cookie_extractor)):
    return {"q_or_cookie": query_or_default}

from fastapi import HTTPException

@app.exception_handler(HTTPException)
async def custom_http_exception_handler(request, exc):
    return JSONResponse(status_code=exc.status_code, content={"message": "Oops! Something went wrong."})

from fastapi.responses import PlainTextResponse

@app.exception_handler(404)
async def not_found_handler(request, exc):
    return PlainTextResponse("Custom 404: Not Found", status_code=404)
